mapper.select:
SELECT g.*, ga.name AS game_name, u.nickname AS author_name, u.avatar AS author_avatar FROM t_guide g LEFT JOIN t_game ga ON g.game_id = ga.id LEFT JOIN t_user u ON g.user_id = u.id WHERE g.status = 1
AND g.game_id = #{gameId}
AND FIND_IN_SET(#{tag}, g.tags)
AND g.title LIKE CONCAT('%', #{keyword}, '%')
ORDER BY g.like_count DESC ORDER BY g.is_top DESC, g.created_at DESC
LIMIT #{offset}, #{size}

mapper.update:
UPDATE t_guide
title = #{title}, content = #{content}, summary = #{summary}, tags = #{tags}, cover = #{cover}, status = #{status},
WHERE id = #{id}
